What does this program print?

```cpp
#include <iostream>
struct Engine {
    int hp;
    Engine(int h) : hp{h} {}
    ~Engine() { std::cout << "Engine gone\n"; }
};
struct Car {
    Engine engine;
    Car(int h) : engine{h} {}
    ~Car() { std::cout << "Car gone\n"; }
};
int main() {
    Car c{200};
}
```

This code is supposed to print a student's name, but it exhibits undefined behavior. Which option correctly identifies the bug?

```cpp
#include <iostream>
#include <string>
struct Student { std::string name; };
struct Classroom {
    Student* enrolled;
};
int main() {
    Classroom room;
    {
        Student s{"Alice"};
        room.enrolled = &s;
    } // s destroyed here
    std::cout << room.enrolled->name << "\n";
}
```
